const webhookBody = $('Receive Project Alert Request')?.first()?.json?.body || {};
const record = $input.item.json.fields || $input.item.json;

// Support both webhook single-project and Airtable batch modes
const project = {
  projectId: webhookBody.projectId || record['Project ID'] || `PROJ-${Date.now()}`,
  projectName: webhookBody.projectName || record['Project Name'] || 'Unnamed Project',
  siteLat: webhookBody.siteLocation?.lat || parseFloat(record['Site Lat']) || -33.8688,
  siteLon: webhookBody.siteLocation?.lon || parseFloat(record['Site Lon']) || 151.2093,
  plannedEndDate: webhookBody.plannedEndDate || record['Planned End Date'] || null,
  currentPhase: webhookBody.currentPhase || record['Current Phase'] || 'Unknown',
  scheduleFloatDays: parseInt(record['Schedule Float Days']) || 10,
  projectManagerEmail: record['Project Manager Email'] || 'user@example.com',
  contractor: record['Contractor'] || 'Unknown',
  budget: record['Budget'] || null,
  jobRunId: `RUN-${Date.now()}-${Math.random().toString(36).substr(2, 6).toUpperCase()}`,
  assessedAt: new Date().toISOString()
};

// Validate critical fields
if (!project.siteLat || !project.siteLon) {
  throw new Error(`Project ${project.projectId} missing site coordinates`);
}

return { json: { project } };

const project = $('Normalize Project Records').item.json.project;
const weatherRaw = $('Fetch 7-Day Site Weather').item.json;
const supplierRaw = $('Fetch Supplier Delivery Status').item.json;
const resourceRaw = $('Fetch Crew & Resource Availability').item.json;

// ── WEATHER ANALYSIS ──
let weatherRisk = { rainDays: 0, highWindDays: 0, extremeHeatDays: 0, frostDays: 0, workableDays: 7, forecastSummary: 'Data unavailable', riskLevel: 'UNKNOWN' };
try {
  const daily = weatherRaw?.daily || [];
  if (daily.length > 0) {
    const rainDays = daily.filter(d => (d.rain || 0) > 5 || (d.pop || 0) > 0.6).length;
    const highWindDays = daily.filter(d => (d.wind_speed || 0) > 15).length;
    const extremeHeatDays = daily.filter(d => (d.temp?.max || 0) > 37).length;
    const frostDays = daily.filter(d => (d.temp?.min || 20) < 2).length;
    const blockedDays = new Set([
      ...daily.filter(d => (d.rain || 0) > 5 || (d.pop || 0) > 0.6).map((_, i) => i),
      ...daily.filter(d => (d.wind_speed || 0) > 15).map((_, i) => i)
    ]).size;
    const workableDays = Math.max(0, 7 - blockedDays);
    const descriptions = [...new Set(daily.slice(0,7).map(d => d.weather?.[0]?.description || ''))];
    weatherRisk = {
      rainDays, highWindDays, extremeHeatDays, frostDays, workableDays,
      forecastSummary: descriptions.join(', ') || 'Partly cloudy',
      riskLevel: rainDays >= 4 ? 'HIGH' : rainDays >= 2 || highWindDays >= 2 ? 'MEDIUM' : 'LOW'
    };
  } else {
    // Synthetic demo fallback
    const rainDays = Math.floor(Math.random() * 4);
    const highWindDays = Math.floor(Math.random() * 2);
    weatherRisk = {
      rainDays, highWindDays, extremeHeatDays: Math.floor(Math.random() * 2),
      frostDays: 0, workableDays: 7 - rainDays - highWindDays,
      forecastSummary: rainDays > 2 ? 'Heavy rain expected mid-week' : 'Mostly clear with isolated showers',
      riskLevel: rainDays >= 4 ? 'HIGH' : rainDays >= 2 ? 'MEDIUM' : 'LOW'
    };
  }
} catch(e) { console.log('Weather parse error:', e.message); }

// ── SUPPLIER ANALYSIS ──
let supplierRisk = { openOrders: 0, delayedOrders: 0, criticalItems: [], avgLeadSlipDays: 0, riskLevel: 'UNKNOWN' };
try {
  const orders = Array.isArray(supplierRaw) ? supplierRaw
    : supplierRaw?.data || supplierRaw?.purchase_orders || [];
  if (orders.length > 0) {
    const delayed = orders.filter(o => o.status === 'delayed' || o.days_late > 0);
    const criticalItems = delayed.filter(o => o.is_critical || o.critical_path).map(o => o.description || o.title);
    const avgSlip = delayed.length > 0
      ? Math.round(delayed.reduce((sum, o) => sum + (o.days_late || 0), 0) / delayed.length)
      : 0;
    supplierRisk = {
      openOrders: orders.length, delayedOrders: delayed.length,
      criticalItems: criticalItems.slice(0, 5), avgLeadSlipDays: avgSlip,
      riskLevel: criticalItems.length > 0 ? 'HIGH' : delayed.length > 2 ? 'MEDIUM' : 'LOW'
    };
  } else {
    // Synthetic
    const delayedOrders = Math.floor(Math.random() * 4);
    const criticalItems = delayedOrders > 1 ? ['Structural Steel (Grade 350)', 'Concrete Pumps'] : [];
    supplierRisk = {
      openOrders: 8 + Math.floor(Math.random() * 10),
      delayedOrders, criticalItems,
      avgLeadSlipDays: delayedOrders > 0 ? Math.floor(Math.random() * 14) + 3 : 0,
      riskLevel: criticalItems.length > 0 ? 'HIGH' : delayedOrders > 1 ? 'MEDIUM' : 'LOW'
    };
  }
} catch(e) { console.log('Supplier parse error:', e.message); }

// ── RESOURCE ANALYSIS ──
let resourceRisk = { totalRoles: 0, understaffedRoles: 0, equipmentIssues: 0, subcontractorRisks: 0, capacityPct: 100, riskLevel: 'UNKNOWN' };
try {
  const resources = Array.isArray(resourceRaw) ? resourceRaw
    : resourceRaw?.records?.map(r => r.fields) || [];
  if (resources.length > 0) {
    const understaffed = resources.filter(r =>
      parseInt(r['Available Count'] || r.available_count || 0) < parseInt(r['Assigned Count'] || r.assigned_count || 1)
    );
    const equipmentIssues = resources.filter(r => (r['Resource Type'] || '').toLowerCase().includes('equipment') && r['Status'] === 'Unavailable').length;
    const subRisks = resources.filter(r => (r['Resource Type'] || '').toLowerCase().includes('sub') && r['Status'] !== 'Confirmed').length;
    const totalCapacity = resources.reduce((s, r) => s + parseInt(r['Assigned Count'] || 1), 0);
    const availCapacity = resources.reduce((s, r) => s + parseInt(r['Available Count'] || 0), 0);
    const capacityPct = totalCapacity > 0 ? Math.round((availCapacity / totalCapacity) * 100) : 100;
    resourceRisk = {
      totalRoles: resources.length, understaffedRoles: understaffed.length,
      equipmentIssues, subcontractorRisks: subRisks, capacityPct,
      riskLevel: understaffed.length > 2 || equipmentIssues > 1 ? 'HIGH' : understaffed.length > 0 ? 'MEDIUM' : 'LOW'
    };
  } else {
    // Synthetic
    const capacityPct = 60 + Math.floor(Math.random() * 40);
    resourceRisk = {
      totalRoles: 6, understaffedRoles: capacityPct < 75 ? 2 : 0,
      equipmentIssues: Math.random() > 0.7 ? 1 : 0,
      subcontractorRisks: Math.random() > 0.6 ? 1 : 0,
      capacityPct,
      riskLevel: capacityPct < 70 ? 'HIGH' : capacityPct < 85 ? 'MEDIUM' : 'LOW'
    };
  }
} catch(e) { console.log('Resource parse error:', e.message); }

// ── SCHEDULE CONTEXT ──
const today = new Date();
const endDate = project.plannedEndDate ? new Date(project.plannedEndDate) : null;
const daysRemaining = endDate ? Math.round((endDate - today) / (1000 * 60 * 60 * 24)) : null;
const floatRatio = daysRemaining && project.scheduleFloatDays
  ? parseFloat((project.scheduleFloatDays / daysRemaining * 100).toFixed(1)) : null;

return {
  json: {
    project,
    riskProfile: {
      weather: weatherRisk,
      supplier: supplierRisk,
      resource: resourceRisk,
      schedule: {
        daysRemaining,
        floatDays: project.scheduleFloatDays,
        floatRatioPct: floatRatio,
        currentPhase: project.currentPhase,
        isNearDeadline: daysRemaining !== null && daysRemaining < 60
      },
      profileBuiltAt: new Date().toISOString()
    }
  }
};

