const aiResponse = $input.item.json;
let aiText = aiResponse.response || aiResponse.output || aiResponse.text || '';

if (aiResponse.content && Array.isArray(aiResponse.content)) {
  aiText = aiResponse.content[0]?.text || '';
}

const cleanText = aiText
  .replace(/```json\s*/g, '')
  .replace(/```\s*/g, '')
  .trim();

let prediction;
try {
  prediction = JSON.parse(cleanText);
} catch (err) {
  const match = cleanText.match(/\{[\s\S]*\}/);
  if (match) { prediction = JSON.parse(match[0]); }
  else { throw new Error(`AI parse failed: ${err.message}. Raw: ${cleanText.substring(0, 300)}`); }
}

const upstream = $('Compile Project Risk Profile').item.json;

// Determine auto-alert flag
const autoAlert = ['CRITICAL', 'HIGH'].includes(prediction.severity);
const priorityLabel = { 'CRITICAL': 'P1_STOP_WORK', 'HIGH': 'P2_URGENT', 'MEDIUM': 'P3_MONITOR', 'LOW': 'P4_WATCH' }[prediction.severity] || 'P3_MONITOR';
const jiraPriority = { 'CRITICAL': 'Highest', 'HIGH': 'High', 'MEDIUM': 'Medium', 'LOW': 'Low' }[prediction.severity] || 'Medium';

return {
  json: {
    project: upstream.project,
    riskProfile: upstream.riskProfile,
    prediction,
    responseDecision: {
      autoAlert,
      priorityLabel,
      jiraPriority,
      createTicket: ['CRITICAL', 'HIGH'].includes(prediction.severity),
      requiresEscalation: prediction.escalateToManagement || prediction.severity === 'CRITICAL',
      slackChannel: prediction.severity === 'CRITICAL' ? '#construction-critical' : prediction.severity === 'HIGH' ? '#construction-alerts' : '#construction-monitoring'
    },
    evaluatedAt: new Date().toISOString()
  }
};

