parameters.jsCode:
const items = $input.all();
const sortedProjects = items
  .map(i => i.json)
  .sort((a, b) => (b.prediction?.delayProbabilityPct || 0) - (a.prediction?.delayProbabilityPct || 0));

const critical = sortedProjects.filter(p => p.prediction?.severity === 'CRITICAL').length;
const high = sortedProjects.filter(p => p.prediction?.severity === 'HIGH').length;
const medium = sortedProjects.filter(p => p.prediction?.severity === 'MEDIUM').length;
const low = sortedProjects.filter(p => p.prediction?.severity === 'LOW').length;

const today = new Date().toLocaleDateString('en-AU', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

let htmlBody = `
<html><body style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;padding:20px;">
<h1 style="color:#1a1a2e;border-bottom:3px solid #e94560;padding-bottom:10px;">🏗️ Construction Delay Risk Briefing</h1>
<p style="color:#555;">${today}</p>

<div style="display:flex;gap:12px;margin:20px 0;">
  <div style="background:#e94560;color:white;padding:15px 25px;border-radius:8px;text-align:center;"><strong style="font-size:2em;">${critical}</strong><br/>CRITICAL</div>
  <div style="background:#ff6b35;color:white;padding:15px 25px;border-radius:8px;text-align:center;"><strong style="font-size:2em;">${high}</strong><br/>HIGH</div>
  <div style="background:#ffa500;color:white;padding:15px 25px;border-radius:8px;text-align:center;"><strong style="font-size:2em;">${medium}</strong><br/>MEDIUM</div>
  <div style="background:#28a745;color:white;padding:15px 25px;border-radius:8px;text-align:center;"><strong style="font-size:2em;">${low}</strong><br/>LOW</div>
</div>

<h2 style="color:#1a1a2e;">Project Risk Summary</h2>
`;

for (const p of sortedProjects.slice(0, 10)) {
  const pred = p.prediction || {};
  const sevColor = { CRITICAL:'#e94560', HIGH:'#ff6b35', MEDIUM:'#ffa500', LOW:'#28a745' }[pred.severity] || '#999';
  htmlBody += `
<div style="border:1px solid #ddd;border-left:5px solid ${sevColor};border-radius:6px;padding:15px;margin:12px 0;">
  <h3 style="margin:0 0 8px;color:#1a1a2e;">${p.project?.projectName || 'Unknown'} <span style="background:${sevColor};color:white;padding:2px 8px;border-radius:4px;font-size:0.75em;">${pred.severity}</span></h3>
  <p style="margin:4px 0;color:#555;"><strong>Phase:</strong> ${p.project?.currentPhase} &nbsp;|&nbsp; <strong>Delay Probability:</strong> ${pred.delayProbabilityPct}% &nbsp;|&nbsp; <strong>Est. Delay:</strong> ${pred.delayDaysRange} days</p>
  <p style="margin:4px 0;color:#555;"><strong>Revised End Date:</strong> ${pred.revisedCompletionDate} &nbsp;|&nbsp; <strong>Budget Impact:</strong> ${pred.budgetImpactEstimate}</p>
  <p style="margin:8px 0 4px;color:#333;">${pred.executiveSummary}</p>
  ${pred.safetyFlags?.length > 0 ? `<p style="color:#e94560;margin:4px 0;">⚠️ Safety: ${pred.safetyFlags.join(', ')}</p>` : ''}
  <p style="margin:8px 0 0;color:#1a1a2e;"><strong>Top Action:</strong> ${pred.recommendedActions?.[0] || 'See full report'}</p>
</div>`;
}

htmlBody += `
<hr style="margin:30px 0;border:1px solid #eee;"/>
<p style="color:#999;font-size:0.85em;">Generated by AI Construction Delay Predictor &bull; ${new Date().toISOString()}</p>
</body></html>`;

return [{
  json: {
    reportDate: today,
    totalProjects: sortedProjects.length,
    summary: { critical, high, medium, low },
    topRiskProjects: sortedProjects.slice(0,5).map(p => ({
      name: p.project?.projectName,
      delayPct: p.prediction?.delayProbabilityPct,
      severity: p.prediction?.severity,
      estimatedDelay: p.prediction?.delayDaysRange
    })),
    htmlBody,
    generatedAt: new Date().toISOString()
  }
}];
